// SearchReplace.cs — .NET 10 file-based app (top-level statements)
// Run with: dotnet run SearchReplace.cs [options]
//
// Usage:
//   dotnet run SearchReplace.cs --dir <directory> --glob <pattern> --search <regex> --replace <text>
//   dotnet run SearchReplace.cs --dir <directory> --glob <pattern> --search <regex> --replace <text> --preview
//   dotnet run SearchReplace.cs --dir <directory> --glob <pattern> --search <regex> --replace <text> --backup
//
// Examples:
//   dotnet run SearchReplace.cs --dir . --glob "**/*.cs" --search "Console\.Write" --replace "Console.WriteLine"
//   dotnet run SearchReplace.cs --dir ./src --glob "**/*.txt" --search "foo" --replace "bar" --preview
//   dotnet run SearchReplace.cs --dir . --glob "**/*.json" --search "localhost" --replace "prod.server.com" --backup

#:sdk Microsoft.NET.Sdk
#:package Microsoft.Extensions.FileSystemGlobbing@10.0.0

using System.Text.RegularExpressions;
using SearchReplace;

// -----------------------------------------------------------------------
// Parse command-line arguments
// -----------------------------------------------------------------------

string? rootDir = null;
string? globPattern = null;
string? searchPattern = null;
string? replacement = null;
bool preview = false;
bool createBackup = false;

for (int i = 0; i < args.Length; i++)
{
    switch (args[i])
    {
        case "--dir":
            rootDir = args[++i];
            break;
        case "--glob":
            globPattern = args[++i];
            break;
        case "--search":
            searchPattern = args[++i];
            break;
        case "--replace":
            replacement = args[++i];
            break;
        case "--preview":
            preview = true;
            break;
        case "--backup":
            createBackup = true;
            break;
        case "--help":
        case "-h":
            PrintUsage();
            return 0;
        default:
            Console.Error.WriteLine($"Unknown argument: {args[i]}");
            PrintUsage();
            return 1;
    }
}

// Validate required arguments
if (rootDir is null || globPattern is null || searchPattern is null || replacement is null)
{
    Console.Error.WriteLine("Error: --dir, --glob, --search, and --replace are all required.");
    PrintUsage();
    return 1;
}

if (!Directory.Exists(rootDir))
{
    Console.Error.WriteLine($"Error: Directory not found: {rootDir}");
    return 1;
}

// -----------------------------------------------------------------------
// Execute
// -----------------------------------------------------------------------

Regex regex;
try
{
    regex = new Regex(searchPattern, RegexOptions.Compiled);
}
catch (RegexParseException ex)
{
    Console.Error.WriteLine($"Error: Invalid regex pattern '{searchPattern}': {ex.Message}");
    return 1;
}

var engine = new SearchReplaceEngine();

Console.WriteLine($"=== Multi-file Search and Replace ===");
Console.WriteLine($"Root directory : {Path.GetFullPath(rootDir)}");
Console.WriteLine($"Glob pattern   : {globPattern}");
Console.WriteLine($"Search regex   : {searchPattern}");
Console.WriteLine($"Replacement    : {replacement}");
Console.WriteLine($"Mode           : {(preview ? "PREVIEW (no files will be modified)" : "REPLACE")}");
Console.WriteLine($"Backup         : {(createBackup ? "yes (.bak files)" : "no")}");
Console.WriteLine();

try
{
    var summary = engine.RunOnDirectory(
        rootDir,
        globPattern,
        regex,
        replacement,
        preview,
        createBackup
    );

    PrintSummary(summary);
    return 0;
}
catch (Exception ex)
{
    Console.Error.WriteLine($"Error: {ex.Message}");
    return 1;
}

// -----------------------------------------------------------------------
// Output helpers
// -----------------------------------------------------------------------

static void PrintSummary(RunSummary summary)
{
    if (summary.FileReports.Count == 0)
    {
        Console.WriteLine("No matches found.");
        return;
    }

    Console.WriteLine($"=== Summary Report ===");
    Console.WriteLine($"Files with matches: {summary.FileReports.Count}");
    Console.WriteLine($"Total changes     : {summary.TotalChanges}");
    Console.WriteLine($"Mode              : {(summary.IsPreview ? "PREVIEW" : "APPLIED")}");
    Console.WriteLine();

    foreach (var report in summary.FileReports)
    {
        Console.WriteLine($"--- File: {report.FilePath} ---");
        if (report.BackupPath is not null)
            Console.WriteLine($"    Backup: {report.BackupPath}");

        foreach (var change in report.Changes)
        {
            Console.WriteLine($"  Line {change.LineNumber,5}:");
            Console.WriteLine($"    OLD: {change.OldText}");
            Console.WriteLine($"    NEW: {change.NewText}");
        }

        Console.WriteLine();
    }
}

static void PrintUsage()
{
    Console.Error.WriteLine("""
        Usage: dotnet run SearchReplace.cs [options]

        Required:
          --dir <path>       Root directory to search recursively
          --glob <pattern>   Glob pattern to match files (e.g. "**/*.cs")
          --search <regex>   Regular expression to search for
          --replace <text>   Replacement text (supports $1, $2 capture groups)

        Optional:
          --preview          Show what would change without modifying files
          --backup           Create .bak backup copies before modifying
          --help, -h         Show this help message

        Examples:
          dotnet run SearchReplace.cs --dir . --glob "**/*.txt" --search "foo" --replace "bar"
          dotnet run SearchReplace.cs --dir ./src --glob "**/*.cs" --search "OldName" --replace "NewName" --preview
          dotnet run SearchReplace.cs --dir . --glob "**/*.json" --search "localhost" --replace "prod.example.com" --backup
        """);
}

